import React, { useState } from "react";

// Ícono de persona (SVG)
const UserIcon = () => (
  <svg style={{ width: "40px", height: "40px", fill: "#333" }} viewBox="0 0 24 24">
    <path d="M12 12c2.76 0 5-2.24 5-5S14.76 2 12 2 7 4.24 7 7s2.24 5 5 5zm0 2c-3.33 0-10 1.67-10 5v3h20v-3c0-3.33-6.67-5-10-5z" />
  </svg>
);

const InicioSesion = ({ onLogin, onClose }) => {
  const [usuario, setUsuario] = useState("");
  const [contrasena, setContrasena] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!usuario || !contrasena) {
      alert("Por favor, rellena todos los campos");
      return;
    }
    if (onLogin) {
      onLogin({ usuario, contrasena });
    } else {
      console.log({ usuario, contrasena });
    }
  };

  // Fondo oscuro que envuelve todo el recuadro de login
  const estilosFondoOscuro = {
    backgroundColor: "rgba(0,0,0,0.7)",
    width: "100%",
    maxWidth: "700px",
    margin: "40px auto",
    padding: "50px",
    borderRadius: "10px",
    display: "flex",
    justifyContent: "center",
    position: "relative",
    fontFamily: "'Merriweather', serif",
  };

  // Recuadro de login (casi blanco) con un tono beige más cálido
  const estilosRecuadro = {
    position: "relative",
    backgroundColor: "rgba(245,230,210,0.95)", // Tono beige más cálido
    borderRadius: "15px",
    width: "400px", // Fijo para mantener el tamaño
    padding: "40px 20px 20px 20px",
    textAlign: "center",
    boxShadow: "0 2px 6px rgba(0,0,0,0.3)",
  };

  // Ícono de persona, centrado arriba y sobresaliendo del recuadro
  const estilosIcono = {
    position: "absolute",
    top: "-20px",
    left: "50%",
    transform: "translateX(-50%)",
    backgroundColor: "rgba(245,230,210,0.95)",
    borderRadius: "50%",
    padding: "6px",
    boxShadow: "0 2px 4px rgba(0,0,0,0.2)",
  };

  // Botón "X" para cerrar, modificado para que sea más simple como en el mockup
  const estilosCerrar = {
    position: "absolute",
    top: "10px",
    right: "15px",
    fontSize: "16px",
    fontWeight: "bold",
    cursor: "pointer",
    color: "#333",
    background: "transparent",
    border: "none",
    zIndex: 10,
  };

  // Título en mayúsculas, con tipografía Merriweather y estilo rústico
  const estilosTitulo = {
    marginTop: "30px",
    marginBottom: "20px",
    fontSize: "20px",
    fontWeight: "bold",
    color: "#333",
    textTransform: "uppercase",
  };

  // Estilos para los inputs, más cortos (70% de ancho)
  const estilosInput = {
    width: "70%",
    margin: "10px auto",
    padding: "10px",
    fontSize: "15px",
    border: "1px solid #bbb",
    borderRadius: "8px",
    outline: "none",
    textAlign: "center",
    backgroundColor: "#fff",
  };

  // Botón Enviar, sin fondo azul, integrado con el recuadro beige
  const estilosBoton = {
    margin: "20px auto 0 auto",
    padding: "8px 20px",
    fontSize: "15px",
    border: "1px solid #333",
    borderRadius: "8px",
    backgroundColor: "transparent",
    color: "#333",
    cursor: "pointer",
    display: "block",
  };

  return (
    <div style={estilosFondoOscuro}>
      <div style={estilosRecuadro}>
        {/* Botón "X" para cerrar - ahora aparece siempre que se proporcione onClose */}
        {onClose && (
          <button style={estilosCerrar} onClick={onClose}>
            ×
          </button>
        )}
        {/* Ícono de persona */}
        <div style={estilosIcono}>
          <UserIcon />
        </div>
        {/* Título */}
        <h2 style={estilosTitulo}>Inicio de Sesión</h2>
        {/* Formulario */}
        <form onSubmit={handleSubmit}>
          <input
            type="text"
            placeholder="Usuario"
            style={estilosInput}
            value={usuario}
            onChange={(e) => setUsuario(e.target.value)}
          />
          <input
            type="password"
            placeholder="Contraseña"
            style={estilosInput}
            value={contrasena}
            onChange={(e) => setContrasena(e.target.value)}
          />
          <button type="submit" style={estilosBoton}>
            Enviar
          </button>
        </form>
      </div>
    </div>
  );
};

export default InicioSesion;
